import axios from 'axios';
import { useEffect, useState } from 'react';
import { LoadingPage } from '../loading-page';
import { LANGUAGES } from '../../i18n/translations';
import MoviesGrid from './movies-grid';
import StartModal from '../start-modal';
import { useUserPreferences } from '../../context/user-preferences';

export function HomePage() {
	const [isLoading, setIsLoading] = useState(false);

	const { language, theme, genres, isModalOpen } = useUserPreferences();

	const token = `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}`;
	const topMoviesUrl = 'https://api.themoviedb.org/3/movie/top_rated?api_key=8a9b6d3eb71a15a13f2cbef497bb7474&language=pt-BR';

	const localStorageGenres = localStorage.getItem('genre-select');

	console.log('localStorageGenres');
	return (
		<div className={`${theme.themeBgClassName} ${theme.themeTextClassName} h-100`}>
			{isLoading ? (
				<LoadingPage />
			) : (
				<>
					<div className="bg-[url('/Users/denzelwallace/Desktop/Me/Estudos/React/dmdb-app/public/assets/background.jpg')] bg-cover backdrop-blur-3xl bg-center text-center p-72">
						<p className="text-9xl font-extrabold text-white">DMDB</p>
						<p className="text-2xl text-white"> {LANGUAGES[language].homePageSubtitle}</p>
					</div>
					{isModalOpen === true || localStorageGenres === null || localStorageGenres === '[]' ? <StartModal /> : ''}
					{localStorageGenres !== null
						? JSON.parse(localStorageGenres).map((g: any) => {
							return <MoviesGrid genre={g.id} type="genre" key={`movie-${g.id}`} />;
						  })
						: genres.map(g => {
							return <MoviesGrid genre={g.id} type="genre" key={`movie-${g.id}`} />;
						  })}
					{/* {genres.map(g => {
						// {localStorage.getItem('genre-select').map(g => {
						return <MoviesGrid genre={g.id} type="genre" key={`movie-${g.id}`} />;
					})} */}
					<MoviesGrid type="top" />
				</>
			)}
		</div>
	);
}
